					toggle?.setAttribute("aria-expanded", "false");
				}, { signal });
			});
		} else {
			menu?.addEventListener("click", (e) => e.stopPropagation(), { signal });
		}
	});

	document.addEventListener("click", (e) => {
		if (!e.target.closest(".chat-dropdown")) {
